import { createSlice } from '@reduxjs/toolkit'
import axios from 'axios'

import { userLoginSucces } from './userLoginSlice'


export const userUpdateProfileSlice = createSlice({
    name: 'userUpdateProfile',
    initialState: {},
    reducers: {
        userUpdateProfileRequest: (state, action) => {
            state.loading = true;
        },

        userUpdateProfileSucces: (state, action) => { 
            state.loading = false;
            state.success = true;
            state.userInfo = action.payload; 
        },

        userUpdateProfileFail: (state, action) => { 
            state.loading = false; 
            state.error = action.payload;
        },

        userUpdateProfileReset: (state) => {
            Object.assign(state, {})
        }
    }
})
export const { userUpdateProfileRequest, userUpdateProfileSucces, userUpdateProfileFail, userLogout } = userUpdateProfileSlice.actions
export default userUpdateProfileSlice.reducer;


// thunk functions to login a user

export const register = (first_name, last_name, email, password) => async (dispatch) => {
    try{
        dispatch(userUpdateProfileRequest())

        const headers = {
            'Content-Type': 'application/json'
        }
        const params = {
            email: email,
            password: password,
            ...(first_name ? { 'first_name': first_name } : {}),
            ...(last_name ? { 'last_name': last_name } : {})
        }

        const { data } = await axios.post(
            'api/users/register/',
            params,
            { headers: headers }
            )

        console.log(data)

        dispatch(userUpdateProfileSucces(data))

        localStorage.setItem('userInfo', JSON.stringify(data))

        // after the user register, log the user in
        dispatch(userLoginSucces(data))

    } catch (error) {
        const msg = (error.response && error.response.data.message ? error.response.data.message : error.message)
        dispatch(userUpdateProfileFail(msg))
    }
}

export const logout = () => (dispatch) => {
    localStorage.removeItem('userInfo')
    dispatch(userLogout())
}
